class Solution(object):
    def shortestSubstrings(self, arr):
        n = len(arr)
        result = ["" for _ in range(n)]
        for i in range(n):
            s = arr[i]
            best = None
            for length in range(1, len(s) + 1):
                candidates = sorted(set(
                    s[start:start + length]
                    for start in range(len(s) - length + 1)
                ))
                for sub in candidates:
                    if not any(sub in arr[j] for j in range(n) if j != i):
                        best = sub
                        break
                if best is not None:
                    break
            result[i] = best if best is not None else ""
        return result
